// Download cover image from URL and prepare all files
const book = $input.first().json;

// Build the complete metadata object for publishing APIs
const publishData = {
  product_id: book.Product_ID,
  book_type: book.Book_Type,

  // Core metadata
  title: book.Title,
  subtitle: book.Subtitle || '',
  author: book.Author || 'ClearStack Studio',
  description_html: book.Description_HTML || book.Title,
  keywords: (book.Keywords || '').split(', ').filter(Boolean),
  categories: (book.Categories || '').split(' | ').filter(Boolean),
  price_usd: parseFloat(book.Price_USD) || 4.99,
  language: 'en',

  // File paths
  interior_pdf: book.Interior_PDF,
  epub_file: book.EPUB_File,
  cover_url: book.Cover_Image_URL,

  // KDP specific
  kdp_select: false, // Set to true for KDP exclusivity - prevents D2D
  page_count: parseInt(book.Page_Count) || 100,

  // Platform routing
  is_ebook: book.Book_Type === 'ebook',
  is_print: book.Book_Type !== 'ebook'
};

return [{ json: publishData }];

