// Generate the complete KDP manual upload guide
// This is the 5-minute guided checklist for the user
const book = $('⚙️ Prep Publish Data').first().json;
const d2dResult = $('📚 Draft2Digital — Publish to All Stores').first().json;
const pdResult = $('🌍 PublishDrive — Upload + Publish').first().json;

// Format keywords as KDP expects (7 keyword fields)
const keywords = book.keywords || [];
const kdpKeywords = keywords.slice(0, 7);
while (kdpKeywords.length < 7) kdpKeywords.push('');

// Build the step-by-step guide
const uploadGuide = {
  product_id: book.product_id,
  title: book.title,

  // Step-by-step KDP upload instructions
  kdp_upload_steps: [
    {
      step: 1,
      action: 'Go to kdp.amazon.com → Click + Create → Select eBook or Paperback',
      notes: book.is_ebook ? 'Select Kindle eBook' : 'Select Paperback'
    },
    {
      step: 2,
      action: 'Book Details — Language',
      value: 'English',
      field: 'Language'
    },
    {
      step: 3,
      action: 'Book Details — Title',
      value: book.title,
      field: 'Book Title'
    },
    {
      step: 4,
      action: 'Book Details — Subtitle',
      value: book.subtitle || '(leave blank)',
      field: 'Subtitle'
    },
    {
      step: 5,
      action: 'Book Details — Author',
      value: 'ClearStack Studio',
      field: 'Primary Author'
    },
    {
      step: 6,
      action: 'Book Details — Description',
      value: 'COPY FROM: ' + book.description_html?.substring(0, 100) + '...',
      field: 'Book Description',
      notes: 'Paste the full HTML description from your KDP_Upload_Queue sheet'
    },
    {
      step: 7,
      action: 'Publishing Rights',
      value: 'I own the copyright and I hold the necessary publishing rights',
      field: 'Publishing Rights'
    },
    {
      step: 8,
      action: 'Keywords — Enter all 7',
      value: kdpKeywords,
      field: 'Keywords (7 fields)'
    },
    {
      step: 9,
      action: 'Categories — Select 2 categories',
      value: (book.categories || []).slice(0, 2),
      field: 'Categories'
    },
    {
      step: 10,
      action: 'Age & Grade Range',
      value: 'Leave blank unless children\'s book',
      field: 'Age Range'
    },
    {
      step: 11,
      action: 'Book Content — Upload manuscript',
      value: book.epub_file || book.interior_pdf,
      field: 'Upload eBook Manuscript / Interior PDF',
      notes: book.is_ebook ? 'Upload the .epub file' : 'Upload the interior PDF'
    },
    {
      step: 12,
      action: 'Book Cover — Upload cover',
      value: 'Download from: ' + book.cover_url,
      field: 'Book Cover',
      notes: 'Download the cover image first, then upload. Min 2560x1600px.'
    },
    {
      step: 13,
      action: 'KDP Select Enrollment',
      value: book.kdp_select ? 'Enroll (90-day exclusivity)' : 'Do NOT enroll (we publish on D2D too)',
      field: 'KDP Select'
    },
    {
      step: 14,
      action: 'Territories',
      value: 'All territories (Worldwide rights)',
      field: 'Territories'
    },
    {
      step: 15,
      action: 'Royalty & Pricing',
      value: `$${book.price_usd} USD — Select 70% royalty if price is $2.99-$9.99, else 35%`,
      field: 'Royalty + List Price'
    },
    {
      step: 16,
      action: 'Click Publish',
      value: 'Takes 24-72 hours to go live on Amazon',
      notes: 'Come back and enter the ASIN in your KDP_Upload_Queue sheet'
    }
  ],

  // Auto-platform results
  auto_published: {
    draft2digital: {
      success: !!d2dResult?.id,
      book_id: d2dResult?.id,
      stores: ['Apple Books', 'Barnes & Noble', 'Kobo', 'Scribd', 'OverDrive', 'Tolino', '35+ more'],
      notes: 'Will go live within 24-72 hours per store'
    },
    publishdrive: {
      success: !!pdResult?.id,
      book_id: pdResult?.id,
      stores: ['Google Play Books', 'Scribd', 'and 400+ more'],
      notes: 'Global distribution including emerging markets'
    }
  },

  estimated_royalties: {
    amazon_kdp_70pct: Math.round(book.price_usd * 0.70 * 100) / 100,
    amazon_kdp_35pct: Math.round(book.price_usd * 0.35 * 100) / 100,
    d2d_65pct: Math.round(book.price_usd * 0.65 * 100) / 100,
    publishdrive_70pct: Math.round(book.price_usd * 0.70 * 100) / 100
  },

  generated_at: new Date().toISOString()
};

return [{ json: uploadGuide }];
